14: GeoipFilterConfig::GeoipFilterConfig(
15:     const envoy::extensions::filters::http::geoip::v3::Geoip& config,
16:     const std::string& stat_prefix, Stats::Scope& scope)
17:     : scope_(scope), stat_name_set_(scope.symbolTable().makeSet("Geoip")),
18:       stats_prefix_(stat_name_set_->add(stat_prefix + "geoip")), use_xff_(config.has_xff_config()),
19:       xff_num_trusted_hops_(config.has_xff_config() ? config.xff_config().xff_num_trusted_hops()
20:                                                     : 0) {
21:   stat_name_set_->rememberBuiltin("total");
22: }
