24: void GeoipFilterConfig::incCounter(Stats::StatName name) {
25:   Stats::SymbolTable::StoragePtr storage = scope_.symbolTable().join({stats_prefix_, name});
26:   scope_.counterFromStatName(Stats::StatName(storage.get())).inc();
27: }
