36: Http::FilterHeadersStatus GeoipFilter::decodeHeaders(Http::RequestHeaderMap& headers, bool) {
37:   // Save request headers for later header manipulation once geolocation lookups are complete.
38:   request_headers_ = headers;
39: 
40:   Network::Address::InstanceConstSharedPtr remote_address;
41:   if (config_->useXff() && config_->xffNumTrustedHops() > 0) {
42:     remote_address =
43:         Envoy::Http::Utility::getLastAddressFromXFF(headers, config_->xffNumTrustedHops()).address_;
44:   }
45:   // If `config_->useXff() == false` or xff header has not been populated for some reason.
46:   if (!remote_address) {
47:     remote_address = decoder_callbacks_->streamInfo().downstreamAddressProvider().remoteAddress();
48:   }
49: 
50:   ASSERT(driver_, "No driver is available to perform geolocation lookup");
51: 
52:   // Capturing weak_ptr to GeoipFilter so that filter can be safely accessed in the posted callback.
53:   // This is a safe measure to protect against the case when filter gets deleted before the callback
54:   // is run.
55:   GeoipFilterWeakPtr self = weak_from_this();
56:   driver_->lookup(
57:       Geolocation::LookupRequest{std::move(remote_address)},
58:       [self, &dispatcher = decoder_callbacks_->dispatcher()](Geolocation::LookupResult&& result) {
59:         dispatcher.post([self, result]() {
60:           if (GeoipFilterSharedPtr filter = self.lock()) {
61:             filter->onLookupComplete(std::move(result));
62:           }
63:         });
64:       });
65: 
66:   // Stop the iteration for headers and data (POST request) for the current filter and the filters
67:   // following.
68:   return Http::FilterHeadersStatus::StopAllIterationAndWatermark;
69: }
70: 
71: Http::FilterDataStatus GeoipFilter::decodeData(Buffer::Instance&, bool) {
72:   return Http::FilterDataStatus::Continue;
73: }
74: 
75: Http::FilterTrailersStatus GeoipFilter::decodeTrailers(Http::RequestTrailerMap&) {
76:   return Http::FilterTrailersStatus::Continue;
77: }
78: 
79: void GeoipFilter::setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) {
80:   decoder_callbacks_ = &callbacks;
81: }
82: 
83: void GeoipFilter::onLookupComplete(Geolocation::LookupResult&& result) {
84:   ASSERT(request_headers_);
85:   for (auto it = result.cbegin(); it != result.cend();) {
86:     const auto& geo_header = it->first;
87:     const auto& lookup_result = it++->second;
88:     if (!lookup_result.empty()) {
89:       request_headers_->setCopy(Http::LowerCaseString(geo_header), lookup_result);
90:     }
91:   }
92:   config_->incTotal();
93:   ENVOY_LOG(debug, "Geoip filter: finished decoding geolocation headers");
94:   decoder_callbacks_->continueDecoding();
95: }
